"use client";

import { ChevronLeft, ChevronRight } from "lucide-react";
import Link from "next/link";
import { useEffect, useState } from "react";

import { getCategoryName, type StorefrontLanguage } from "@/lib/storefront";
import type { Category } from "@/lib/types";
import { cn } from "@/lib/utils";

type CarouselProps = {
  categories: Category[];
  language: StorefrontLanguage;
};

type CarouselButtonProps = {
  side: "left" | "right";
  label: string;
  disabled: boolean;
  onClick: () => void;
};

function chunkItems<T>(items: T[], size: number) {
  if (size <= 0 || items.length === 0) {
    return items.length > 0 ? [items] : [];
  }

  const chunks: T[][] = [];

  for (let index = 0; index < items.length; index += size) {
    chunks.push(items.slice(index, index + size));
  }

  return chunks;
}

function getQuickCategoryColumns(width: number) {
  if (width >= 1280) {
    return 6;
  }

  if (width >= 1024) {
    return 4;
  }

  if (width >= 640) {
    return 3;
  }

  return 2;
}

function CarouselButton({
  side,
  label,
  disabled,
  onClick,
}: CarouselButtonProps) {
  return (
    <button
      type="button"
      aria-label={label}
      onClick={onClick}
      disabled={disabled}
      className={cn(
        "flex h-11 w-11 shrink-0 items-center justify-center rounded-full border border-slate-200 bg-white text-[#1D1D1F] transition duration-200",
        disabled
          ? "cursor-not-allowed opacity-45"
          : "hover:border-primary/40 hover:text-primary hover:shadow-soft"
      )}
    >
      {side === "left" ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
    </button>
  );
}

function QuickCategoryCard({
  category,
  language,
  textAlignClass,
}: {
  category: Category;
  language: StorefrontLanguage;
  textAlignClass: string;
}) {
  return (
    <Link
      href={`/category/${category.id}`}
      className="group rounded-[2rem] border border-slate-200 bg-white p-4 shadow-soft transition duration-300 hover:-translate-y-1 hover:border-primary/20 hover:shadow-premium"
    >
      <div className="overflow-hidden rounded-[1.5rem] bg-slate-100">
        {category.image_url ? (
          <img
            src={category.image_url}
            alt={getCategoryName(category, language)}
            className="aspect-square w-full object-cover transition duration-500 group-hover:scale-105"
            loading="lazy"
          />
        ) : (
          <div className="flex aspect-square items-center justify-center bg-[linear-gradient(135deg,#eff7ef_0%,#f8fbf8_100%)] text-4xl text-primary">
            {category.icon?.slice(0, 1) || "•"}
          </div>
        )}
      </div>
      <p
        className={cn(
          "mt-4 line-clamp-2 text-base font-semibold text-[#1D1D1F]",
          textAlignClass
        )}
      >
        {getCategoryName(category, language)}
      </p>
    </Link>
  );
}

function DepartmentCard({
  category,
  language,
  textAlignClass,
}: {
  category: Category;
  language: StorefrontLanguage;
  textAlignClass: string;
}) {
  return (
    <Link
      href={`/category/${category.id}`}
      className="group flex h-full flex-col overflow-hidden rounded-xl border border-slate-200 bg-white transition duration-300 hover:border-primary/20"
    >
      <div className="overflow-hidden bg-slate-100">
        {category.image_url ? (
          <img
            src={category.image_url}
            alt={getCategoryName(category, language)}
            className="aspect-[4/4.4] w-full object-cover transition duration-500 group-hover:scale-105"
            loading="lazy"
          />
        ) : (
          <div className="flex aspect-[4/4.4] items-center justify-center bg-[linear-gradient(135deg,#f1f8f1_0%,#fbfcfb_100%)] text-4xl text-primary">
            {category.icon?.slice(0, 1) || "•"}
          </div>
        )}
      </div>

      <div className="px-2.5 py-3 sm:px-3">
        <h3
          className={cn(
            "line-clamp-2 text-xs font-semibold text-[#1D1D1F] sm:text-base",
            textAlignClass
          )}
        >
          {getCategoryName(category, language)}
        </h3>
      </div>
    </Link>
  );
}

export function QuickCategoriesCarousel({
  categories,
  language,
}: CarouselProps) {
  const isRTL = language === "ar";
  const textAlignClass = isRTL ? "text-right" : "text-left";
  const [currentPage, setCurrentPage] = useState(0);
  const [columns, setColumns] = useState(2);

  useEffect(() => {
    const handleResize = () => {
      setColumns(getQuickCategoryColumns(window.innerWidth));
    };

    handleResize();
    window.addEventListener("resize", handleResize);

    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const pageSize = columns * 2;
  const pages = chunkItems(categories, pageSize);
  const pageCount = pages.length;
  const activePage = Math.min(currentPage, Math.max(pageCount - 1, 0));

  const previousLabel =
    language === "ar" ? "التصنيفات السابقة" : "Previous categories";
  const nextLabel = language === "ar" ? "التصنيفات التالية" : "Next categories";

  if (pageCount === 0) {
    return null;
  }

  return (
    <div className="mt-6 grid grid-cols-[auto_1fr_auto] items-center gap-2 sm:gap-4">
      {isRTL ? (
        <CarouselButton
          side="right"
          label={previousLabel}
          disabled={activePage === 0}
          onClick={() => setCurrentPage((page) => Math.max(page - 1, 0))}
        />
      ) : (
        <CarouselButton
          side="left"
          label={previousLabel}
          disabled={activePage === 0}
          onClick={() => setCurrentPage((page) => Math.max(page - 1, 0))}
        />
      )}

      <div className="min-w-0 overflow-hidden">
        <div
          className="flex transition-transform duration-500 ease-out"
          style={{ transform: `translate3d(-${activePage * 100}%, 0, 0)` }}
        >
          {pages.map((pageCategories, pageIndex) => (
            <div
              key={`quick-categories-page-${pageIndex}`}
              className="grid min-w-full grid-cols-2 gap-4 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6"
            >
              {pageCategories.map((category) => (
                <QuickCategoryCard
                  key={category.id}
                  category={category}
                  language={language}
                  textAlignClass={textAlignClass}
                />
              ))}

              {Array.from({
                length: Math.max(0, pageSize - pageCategories.length),
              }).map((_, index) => (
                <div
                  key={`quick-category-empty-${pageIndex}-${index}`}
                  aria-hidden="true"
                  className="invisible"
                />
              ))}
            </div>
          ))}
        </div>
      </div>

      {isRTL ? (
        <CarouselButton
          side="left"
          label={nextLabel}
          disabled={activePage >= pageCount - 1}
          onClick={() =>
            setCurrentPage((page) => Math.min(page + 1, pageCount - 1))
          }
        />
      ) : (
        <CarouselButton
          side="right"
          label={nextLabel}
          disabled={activePage >= pageCount - 1}
          onClick={() =>
            setCurrentPage((page) => Math.min(page + 1, pageCount - 1))
          }
        />
      )}
    </div>
  );
}

